const { AzureFunction, Context } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

// Set function timeout to maximum (10 minutes for Consumption plan)
exports.handler = async function (context: Context, req: any) {
    context.log('Azure Function started');

    // Disable timeout enforcement where possible
    process.env.AZURE_FUNCTION_WORKER_DISABLE_TIMEOUT_ENFORCEMENT = 'true';

    const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);
    const databaseName = process.env.COSMOS_DB_DATABASE_NAME;
    const containerName = process.env.COSMOS_DB_CONTAINER_NAME;

    try {
        // Get a reference to the database
        const database = await cosmosClient.database(databaseName).read();

        // Get a reference to the container
        const container = await database.container(containerName).read();

        // Process large datasets from Cosmos DB
        const querySpec = {
            query: 'SELECT * FROM c',
        };

        const { resources } = await container.items.query(querySpec).fetchAll();
        context.log('Fetched items from Cosmos DB');

        // Simulate processing of large dataset (e.g., 10 minutes)
        for (let i = 0; i < 600; i++) {
            await new Promise(resolve => setTimeout(resolve, 10000));
            context.log(`Processed ${i} seconds`);
        }

        context.log('Completed processing large dataset');
    } catch (error) {
        context.log.error(error);
        throw error;
    }
};